//! standing-wave-parity — runs the same prompt through two pipelines (one with
//! standing-wave routing simulation enabled, one without) and compares logit
//! distributions. This is the only honest answer to "does compression preserve
//! the model's output?"
//!
//! Usage:
//!   standing-wave-parity \
//!     --knot /path/to/model.knot \
//!     --tokens 1,2,3,4
//!
//! Prints per-step:
//!   - top-1 token agreement (baseline argmax == compressed argmax)
//!   - top-5 overlap (Jaccard)
//!   - cosine similarity of full logit vectors
//!   - max-abs delta between logits
//!
//! Exits non-zero if the binary couldn't load the knot or run forward_one.
//! Does NOT assert any pass/fail threshold — the operator reads the numbers
//! and decides if compression is acceptable for their use case.

use std::env;
use std::time::Instant;

use distributed_inference::loader::KnotWeights;
use distributed_inference::NativeLlamaPipeline;

struct Args {
    knot_path: String,
    tokens: Vec<u32>,
    coverages: Vec<f32>,
    delta_only: bool,
    mean_fill: bool,
    orthogonal: bool,
    /// None = inject at every boundary; Some(L) = inject only at L→L+1 boundary.
    inject_at_layer: Option<usize>,
    /// None = ignored; Some(set) = inject only at boundaries in the set.
    /// Takes precedence over inject_at_layer.
    inject_at_layers: Option<Vec<usize>>,
    /// When set with no `--inject-at-layer`, sweeps single-layer injection
    /// across [0, num_layers) for a per-layer damage profile. Implies all
    /// other coverage/mode flags applied to each single-boundary run.
    sweep_per_layer: bool,
}

fn parse_args() -> Result<Args, String> {
    let argv: Vec<String> = env::args().collect();
    let mut knot_path: Option<String> = None;
    let mut tokens: Option<Vec<u32>> = None;
    let mut coverages: Vec<f32> = vec![0.30];
    let mut delta_only = false;
    let mut mean_fill = false;
    let mut orthogonal = false;
    let mut inject_at_layer: Option<usize> = None;
    let mut inject_at_layers: Option<Vec<usize>> = None;
    let mut sweep_per_layer = false;
    let mut i = 1;
    while i < argv.len() {
        match argv[i].as_str() {
            "--knot" => {
                i += 1;
                knot_path = Some(argv.get(i).ok_or("--knot needs a value")?.clone());
            }
            "--tokens" => {
                i += 1;
                let raw = argv.get(i).ok_or("--tokens needs a value")?;
                let parsed: Vec<u32> = raw
                    .split(',')
                    .map(|s| {
                        s.trim()
                            .parse::<u32>()
                            .map_err(|e| format!("bad token {:?}: {}", s, e))
                    })
                    .collect::<Result<_, _>>()?;
                tokens = Some(parsed);
            }
            "--coverage" => {
                i += 1;
                let raw = argv.get(i).ok_or("--coverage needs a value")?;
                coverages = raw
                    .split(',')
                    .map(|s| {
                        s.trim()
                            .parse::<f32>()
                            .map_err(|e| format!("bad coverage {:?}: {}", s, e))
                    })
                    .collect::<Result<_, _>>()?;
            }
            "--delta-only" => {
                delta_only = true;
            }
            "--mean-fill" => {
                mean_fill = true;
            }
            "--orthogonal" => {
                orthogonal = true;
            }
            "--inject-at-layer" => {
                i += 1;
                let raw = argv.get(i).ok_or("--inject-at-layer needs a value")?;
                inject_at_layer = Some(
                    raw.parse::<usize>()
                        .map_err(|e| format!("bad layer {:?}: {}", raw, e))?,
                );
            }
            "--inject-at-layers" => {
                i += 1;
                let raw = argv
                    .get(i)
                    .ok_or("--inject-at-layers needs a comma-separated list")?;
                let parsed: Vec<usize> = raw
                    .split(',')
                    .map(|s| {
                        s.trim()
                            .parse::<usize>()
                            .map_err(|e| format!("bad layer {:?}: {}", s, e))
                    })
                    .collect::<Result<_, _>>()?;
                inject_at_layers = Some(parsed);
            }
            "--sweep-per-layer" => {
                sweep_per_layer = true;
            }
            other => return Err(format!("unknown arg: {}", other)),
        }
        i += 1;
    }
    Ok(Args {
        knot_path: knot_path.ok_or("--knot is required")?,
        tokens: tokens.ok_or("--tokens is required")?,
        coverages,
        delta_only,
        mean_fill,
        orthogonal,
        inject_at_layer,
        inject_at_layers,
        sweep_per_layer,
    })
}

fn build_pipeline(knot_path: &str) -> Result<NativeLlamaPipeline, String> {
    let knot = KnotWeights::load(knot_path).map_err(|e| format!("knot load failed: {:?}", e))?;
    Ok(NativeLlamaPipeline::from_knot(knot, false, 0.8))
}

fn topk_indices(logits: &[f32], k: usize) -> Vec<usize> {
    let mut idx: Vec<usize> = (0..logits.len()).collect();
    idx.sort_by(|&a, &b| {
        logits[b]
            .partial_cmp(&logits[a])
            .unwrap_or(std::cmp::Ordering::Equal)
    });
    idx.truncate(k);
    idx
}

fn jaccard(a: &[usize], b: &[usize]) -> f32 {
    use std::collections::HashSet;
    let sa: HashSet<usize> = a.iter().copied().collect();
    let sb: HashSet<usize> = b.iter().copied().collect();
    let inter = sa.intersection(&sb).count() as f32;
    let union = sa.union(&sb).count() as f32;
    if union == 0.0 {
        0.0
    } else {
        inter / union
    }
}

fn cosine(a: &[f32], b: &[f32]) -> f32 {
    let mut dot = 0.0f32;
    let mut na = 0.0f32;
    let mut nb = 0.0f32;
    for i in 0..a.len() {
        dot += a[i] * b[i];
        na += a[i] * a[i];
        nb += b[i] * b[i];
    }
    let denom = na.sqrt() * nb.sqrt();
    if denom == 0.0 {
        0.0
    } else {
        dot / denom
    }
}

fn max_abs_delta(a: &[f32], b: &[f32]) -> f32 {
    a.iter()
        .zip(b.iter())
        .map(|(x, y)| (x - y).abs())
        .fold(0.0f32, f32::max)
}

/// log-softmax of logits in-place — numerically stable (subtract max).
fn log_softmax(logits: &[f32]) -> Vec<f32> {
    let m = logits.iter().copied().fold(f32::NEG_INFINITY, f32::max);
    let exps: Vec<f32> = logits.iter().map(|&v| (v - m).exp()).collect();
    let sum: f32 = exps.iter().sum();
    let log_sum = m + sum.ln();
    logits.iter().map(|&v| v - log_sum).collect()
}

/// KL(P || Q) where P=baseline, Q=compressed. Both passed as raw logits.
fn kl_divergence(baseline_logits: &[f32], compressed_logits: &[f32]) -> f32 {
    let lp = log_softmax(baseline_logits);
    let lq = log_softmax(compressed_logits);
    let mut kl = 0.0f32;
    for i in 0..lp.len() {
        let p = lp[i].exp();
        if p > 1e-12 {
            kl += p * (lp[i] - lq[i]);
        }
    }
    kl
}

/// Margin between top-1 and top-2 logits in the baseline (a measure of how
/// confident the model was — if the margin is huge, even bad reconstruction
/// might still pick the right argmax).
fn baseline_margin(baseline_logits: &[f32]) -> f32 {
    let mut top = f32::NEG_INFINITY;
    let mut second = f32::NEG_INFINITY;
    for &v in baseline_logits {
        if v > top {
            second = top;
            top = v;
        } else if v > second {
            second = v;
        }
    }
    top - second
}

struct RunResult {
    top1_agree: usize,
    top5_contains_baseline: usize,
    compared: usize,
    top5_jaccard_sum: f64,
    cosine_sum: f64,
    max_abs_sum: f64,
    kl_sum: f64,
    margin_sum: f64,
    baseline_ms: u128,
    compressed_ms: u128,
}

#[allow(clippy::too_many_arguments)]
fn run_one(
    knot_path: &str,
    tokens: &[u32],
    coverage: f32,
    delta_only: bool,
    mean_fill: bool,
    orthogonal: bool,
    inject_at_layer: Option<usize>,
    inject_at_layers: Option<Vec<usize>>,
) -> Result<RunResult, String> {
    let mut baseline = build_pipeline(knot_path)?;
    let mut compressed = build_pipeline(knot_path)?;
    compressed.set_standing_wave_simulate_routing(true);
    compressed.set_standing_wave_target_coverage(coverage);
    compressed.set_standing_wave_route_delta_only(delta_only);
    compressed.set_standing_wave_use_mean_fill(mean_fill);
    compressed.set_standing_wave_use_orthogonal(orthogonal);
    compressed.set_standing_wave_inject_at_layer(inject_at_layer);
    compressed.set_standing_wave_inject_at_layers(inject_at_layers);

    let mut r = RunResult {
        top1_agree: 0,
        top5_contains_baseline: 0,
        compared: 0,
        top5_jaccard_sum: 0.0,
        cosine_sum: 0.0,
        max_abs_sum: 0.0,
        kl_sum: 0.0,
        margin_sum: 0.0,
        baseline_ms: 0,
        compressed_ms: 0,
    };

    for (step, &token) in tokens.iter().enumerate() {
        let t_b = Instant::now();
        baseline
            .forward_one(token as usize, step, false)
            .map_err(|e| {
                format!(
                    "baseline forward_one(token={}, step={}): {}",
                    token, step, e
                )
            })?;
        let baseline_ms = t_b.elapsed().as_millis();

        let t_c = Instant::now();
        compressed
            .forward_one(token as usize, step, false)
            .map_err(|e| {
                format!(
                    "compressed forward_one(token={}, step={}): {}",
                    token, step, e
                )
            })?;
        let compressed_ms = t_c.elapsed().as_millis();

        if step == 0 {
            continue;
        }

        r.baseline_ms += baseline_ms;
        r.compressed_ms += compressed_ms;

        let bl = baseline.get_logits();
        let cl = compressed.get_logits();
        if bl.len() != cl.len() {
            return Err(format!(
                "logit shape mismatch: baseline={} compressed={}",
                bl.len(),
                cl.len()
            ));
        }

        let bl_top1 = topk_indices(bl, 1);
        let cl_top1 = topk_indices(cl, 1);
        let bl_top5 = topk_indices(bl, 5);
        let cl_top5 = topk_indices(cl, 5);

        if bl_top1[0] == cl_top1[0] {
            r.top1_agree += 1;
        }
        if cl_top5.contains(&bl_top1[0]) {
            r.top5_contains_baseline += 1;
        }
        r.top5_jaccard_sum += jaccard(&bl_top5, &cl_top5) as f64;
        r.cosine_sum += cosine(bl, cl) as f64;
        r.max_abs_sum += max_abs_delta(bl, cl) as f64;
        r.kl_sum += kl_divergence(bl, cl) as f64;
        r.margin_sum += baseline_margin(bl) as f64;
        r.compared += 1;
    }

    Ok(r)
}

fn print_row(
    label: &str,
    cov: f32,
    delta_only: bool,
    mean_fill: bool,
    orthogonal: bool,
    r: &RunResult,
) {
    if r.compared == 0 {
        println!(
            "{} cov={:.2} delta={} mean={} orth={} compared=0",
            label, cov, delta_only, mean_fill, orthogonal
        );
        return;
    }
    let n = r.compared as f64;
    let slowdown = if r.baseline_ms > 0 {
        r.compressed_ms as f64 / r.baseline_ms as f64
    } else {
        f64::NAN
    };
    println!(
        "{} cov={:.2} delta={} mean={} orth={} top1={}/{}={:.0}% top5_has_bl={}/{}={:.0}% top5_jaccard={:.3} cosine={:.4} max_abs={:.2} KL={:.4} margin={:.2} slowdown={:.2}x",
        label,
        cov,
        delta_only,
        mean_fill,
        orthogonal,
        r.top1_agree,
        r.compared,
        100.0 * r.top1_agree as f64 / n,
        r.top5_contains_baseline,
        r.compared,
        100.0 * r.top5_contains_baseline as f64 / n,
        r.top5_jaccard_sum / n,
        r.cosine_sum / n,
        r.max_abs_sum / n,
        r.kl_sum / n,
        r.margin_sum / n,
        slowdown,
    );
}

fn main() -> Result<(), String> {
    let args = parse_args().inspect_err(|_| {
        eprintln!("usage: standing-wave-parity --knot PATH --tokens IDS [--coverage A,B,...] [--delta-only] [--mean-fill] [--orthogonal] [--inject-at-layer L | --sweep-per-layer]");
    })?;

    eprintln!("[parity] knot={}", args.knot_path);
    eprintln!(
        "[parity] tokens={} coverages={:?}",
        args.tokens.len(),
        args.coverages
    );
    eprintln!(
        "[parity] modes: delta_only={} mean_fill={} orthogonal={} inject_at_layer={:?} sweep_per_layer={}",
        args.delta_only, args.mean_fill, args.orthogonal, args.inject_at_layer, args.sweep_per_layer
    );

    if args.sweep_per_layer {
        // Discover num_layers from a one-time pipeline build.
        let probe = build_pipeline(&args.knot_path)?;
        let num_layers = probe.num_layers();
        drop(probe);
        eprintln!("[parity] sweep_per_layer: probing {} layers", num_layers);
        for &cov in &args.coverages {
            for l in 0..num_layers.saturating_sub(1) {
                let r = run_one(
                    &args.knot_path,
                    &args.tokens,
                    cov,
                    args.delta_only,
                    args.mean_fill,
                    args.orthogonal,
                    Some(l),
                    None,
                )?;
                let label = format!("inject_l={:>2}", l);
                print_row(
                    &label,
                    cov,
                    args.delta_only,
                    args.mean_fill,
                    args.orthogonal,
                    &r,
                );
            }
        }
        return Ok(());
    }

    for &cov in &args.coverages {
        let r = run_one(
            &args.knot_path,
            &args.tokens,
            cov,
            args.delta_only,
            args.mean_fill,
            args.orthogonal,
            args.inject_at_layer,
            args.inject_at_layers.clone(),
        )?;
        let label = match (&args.inject_at_layers, args.inject_at_layer) {
            (Some(ls), _) => format!("inject_set={:?}", ls),
            (None, Some(l)) => format!("inject_l={}", l),
            (None, None) => "all".to_string(),
        };
        print_row(
            &label,
            cov,
            args.delta_only,
            args.mean_fill,
            args.orthogonal,
            &r,
        );
    }
    Ok(())
}
